if (typeof msg.payload === "string") {
    try {
        msg.payload = JSON.parse(msg.payload);
    } catch (e) {
        node.warn("Invalid JSON");
        return null;
    }
}
const data = msg.payload.Data;
if (!Array.isArray(data)) return null;

const variableMap = flow.get("variableMap") || {};
for (const item of data) {
    if (item.valid && typeof item.id === "number" && typeof item.val === "number") {
        for (const [expId, entry] of Object.entries(variableMap)) {
            if (entry.goFreeId === item.id) {

                flow.set(entry.name, item.val);
                flow.set(`${entry.name}_updated`, Date.now());
                flow.set("lastValidUpdate", Date.now());
                break;
            }
        }
    }
}
return null;

function emit(msgObj, delay) {
    setTimeout(() => {
        node.send({ payload: msgObj });
    }, delay);
}

const variableMap = flow.get("variableMap") || {};
const ids = Object.values(variableMap)
    .map(entry => entry.goFreeId)
    .filter(id => typeof id === "number");

let t = 0;
emit({ Authentication: { id: 0 } }, t += 0);
emit({ ProductIdReq: [] },      t += 200);
emit({ FriendlyNameReq: [] },   t += 200);
emit({ SettingInfoReq: [14,15,17,18,19,20,21] }, t += 200);
emit({ EventReg: [5,10,21,24] }, t += 200);
emit({ EventSet: [{ id: 21, action: "request" }] }, t += 200);

// Build bulk DataReq
const dataReq = {
    DataReq: ids.map(id => ({ id, repeat: true, inst: 0 }))
};
emit(dataReq, t += 200);

return null;

const connected = msg.status?.text === "connected";
const lastSubscribed = flow.get("subscribed_ok") || false;
const now = Date.now();
const lastTime = flow.get("subscribed_time") || 0;

if (connected) {
    const timeSince = now - lastTime;

    if (!lastSubscribed || timeSince > 10000) { // every 10s max
        flow.set("subscribed_ok", true);
        flow.set("subscribed_time", now);
        return { payload: "trigger" };
    }
} else {
    flow.set("subscribed_ok", false);
    flow.set("subscribed_time", 0);
}
return null;
